INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L2_A', 'P2e', 2, 'A', 'Categorizing probability', NULL, NULL, NULL, NULL, NULL, 'Say: ''I am going to read a sentence. Tell me if it is Certain, Likely, Unlikely, or Impossible: You will drink water sometime this week.''', 'Child categorizes the statement as ''Certain'' (or very likely depending on the child''s interpretation, but ''Certain'' is technically correct for biological needs over a week).', 'Child says Impossible or Unlikely.', 'Why isn''t it just ''likely''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L2_B', 'P2e', 2, 'B', 'Categorizing probability', NULL, NULL, NULL, NULL, NULL, 'Show a bag with 9 green marbles and 1 yellow marble. Say: ''Is pulling a green marble likely, unlikely, or certain?''', 'Child identifies ''Likely''.', 'Child says ''Certain'' (forgetting the yellow marble) or ''Unlikely''.', 'Why isn''t it ''Certain''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L2_C', 'P2e', 2, 'C', 'Categorizing probability', NULL, NULL, NULL, NULL, NULL, 'Show a spinner that is half red, half blue. Say: ''Is spinning red likely, unlikely, or equally likely as spinning blue?''', 'Child identifies ''Equally likely''.', 'Child guesses one color over the other.', 'If I color a little more of the spinner red, what happens to the chances?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L3_A', 'P2e', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend bought one lottery ticket. They said, "I am likely to win because there are only two choices: win or lose." Are they right? Why?''', 'Child explains that ''two choices'' does not mean ''equally likely'', and losing is much more likely because there are millions of losing tickets.', 'Child agrees with the friend.', 'If there is 1 winning ticket and 100 losing tickets, is it still a 50/50 chance?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L3_B', 'P2e', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a bag with 5 red blocks and 5 blue blocks. Say: ''My friend reached in 3 times and pulled out a red block every time. They say, "The bag must have more red blocks." Are they right? Why?''', 'Child explains that it is possible to pull the same color multiple times even if the amounts are equal, so the friend isn''t necessarily right.', 'Child agrees with the friend.', 'If they pulled 100 blocks, do you think they would all be red?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L3_C', 'P2e', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a picture of a six-sided die. Say: ''Someone says it is impossible to roll a 7. Is that true? Why?''', 'Child confirms it is true because the numbers only go up to 6.', 'Child thinks a 7 can be rolled if they throw it hard enough.', 'What would you have to do to the dice to make rolling a 7 possible?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_A', 'P2e', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Tell me something that is impossible to happen today, and something that is certain to happen today.''', 'Child generates two accurate statements demonstrating understanding of the extremes of probability.', 'Child confuses likely/unlikely with certain/impossible.', 'If you say ''The sun will shine today'', is that certain or just likely?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_B', 'P2e', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Draw a spinner with three colors: Red, Blue, and Green. Make it so that spinning Red is very likely, spinning Blue is unlikely, and spinning Green is impossible.''', 'Child draws a spinner mostly Red, a small sliver of Blue, and no Green section.', 'Child draws equal sections, or includes Green.', 'How would you change the drawing to make Blue and Red equally likely?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_C', 'P2e', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Make up a game with a coin where you have an unfair advantage over me. Explain the rules.''', 'Child creates rules where their winning condition has higher probability (e.g., ''If it lands heads OR tails, I win. If it lands on its edge, you win.'').', 'Child creates a fair game (e.g., heads I win, tails you win), or impossible rules.', 'How would you fix the game to make it fair for both of us?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_M', 'P2e', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'You are planning a picnic for Saturday. The weather report says there is a 90% chance of heavy rain. Should you plan to have the picnic outside or inside? Why?', 'Child chooses inside because heavy rain is very likely.', 'Child chooses outside because they like picnics, ignoring the high probability of rain.', 'If the report said there was a 10% chance of rain, would you change your mind? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L1_A', 'P2f', 1, 'A', 'Physical experiment', 'A coin, Paper, Pencil', NULL, NULL, NULL, NULL, 'Say: ''Flip this coin 10 times. Draw a tally mark for each Head and each Tail you get.''', 'Child successfully completes the physical experiment and records the 10 results.', 'Child predicts the outcome without flipping, loses count, or records incorrectly.', 'Did you get exactly 5 Heads and 5 Tails? Why or why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L1_B', 'P2f', 1, 'B', 'Physical experiment', 'A 6-sided die, Paper, Pencil', NULL, NULL, NULL, NULL, 'Say: ''Roll the die 6 times. Write down the numbers you roll.''', 'Child completes the rolling and accurately records the 6 numbers.', 'Child expects to get 1, 2, 3, 4, 5, 6 in order or stops after fewer rolls.', 'Did you roll every number from 1 to 6? Why do you think that happened?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L1_C', 'P2f', 1, 'C', 'Physical experiment', 'A bag, 3 red blocks, 1 blue block, Paper, Pencil', NULL, NULL, NULL, NULL, 'Put the blocks in the bag. Say: ''Without looking, pull a block out, write down its color, and put it back. Do this 5 times.''', 'Child pulls, records, replaces the block, and repeats 5 times.', 'Child doesn''t replace the block, altering the probability for subsequent pulls.', 'Why is it important to put the block back in the bag every time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L2_A', 'P2f', 2, 'A', 'Analyzing experiment data', NULL, NULL, NULL, NULL, NULL, 'Say: ''I flipped a coin 20 times. Here are my results: 14 Heads, 6 Tails. Did I get the expected 10 Heads and 10 Tails?''', 'Child correctly identifies that the results were not 10 and 10, recognizing variance.', 'Child thinks the coin must be broken or rigged.', 'If you flipped a coin 100 times, do you think you would get exactly 50 Heads?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L2_B', 'P2f', 2, 'B', 'Analyzing experiment data', NULL, NULL, NULL, NULL, NULL, 'Show a tally chart for rolling a die 12 times: 1 (II), 2 (I), 3 (IIII), 4 (II), 5 (I), 6 (II). Say: ''Which number was rolled the most? Which the least?''', 'Child identifies 3 as most (4 rolls) and 2 or 5 as least (1 roll).', 'Child identifies 6 as most because it''s the highest number on the die.', 'Why didn''t every number get rolled 2 times?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L2_C', 'P2f', 2, 'C', 'Analyzing experiment data', NULL, NULL, NULL, NULL, NULL, 'Say: ''I pulled a block from a bag 10 times, replacing it each time. I got Red 8 times and Blue 2 times. If you reached in, what color do you think you would probably get?''', 'Child infers that Red is the most likely color in the bag and predicts pulling Red.', 'Child predicts Blue, or cannot articulate why Red is more likely.', 'Are you absolutely certain you will pull a Red block next time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L3_A', 'P2f', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend flipped a coin 5 times and got Heads every time. They say the 6th flip WILL definitely be Tails because it''s "due". Why is this wrong?''', 'Child explains that the coin does not have a memory, so the chance is still equal.', 'Child agrees with the friend.', 'Does the coin remember what it did before?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L3_B', 'P2f', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''We rolled a die 6 times and never rolled a 4. My friend said, "The die is broken! It should have landed on 4 once!" Are they right? Why?''', 'Child explains that rolling each number exactly once in 6 rolls is unlikely, and variance is normal.', 'Child thinks the die must be flawed.', 'If you rolled it 100 times, do you think a 4 would show up?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L3_C', 'P2f', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a bag of 5 red blocks and 1 blue block. Say: ''My friend pulled a blue block on their first try! They said, "Wow, blue must be the most common color in the bag." Why are they wrong?''', 'Child points out that pulling a rare color on the first try is possible, but it doesn''t change the actual amount in the bag.', 'Child agrees with the friend''s conclusion based on the single pull.', 'If they pulled 10 more blocks, what color do you think they would mostly get?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_A', 'P2f', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Design a simple experiment using a coin to decide who gets to go first in a game. Then play it out to show me the result.''', 'Child assigns Heads to one person and Tails to another, flips the coin, and declares the winner.', 'Child flips the coin without assigning outcomes, or creates an unfair rule.', 'If the coin lands on the floor and you can''t see it, what should you do?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_B', 'P2f', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Make up an experiment with a six-sided die where I have a likely chance of winning, and you have an unlikely chance of winning.''', 'Child creates rules such as ''If it lands on 1, 2, 3, 4, or 5, you win. If it lands on 6, I win.''', 'Child creates a fair game (e.g., odds vs evens) or an impossible game.', 'How many winning numbers do you have compared to my winning numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_C', 'P2f', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Explain why flipping a coin 100 times gives you a better idea of what to expect than flipping it just 2 times.''', 'Child explains that small amounts of flips can have streaks, but more flips show the true, steady pattern (closer to half and half).', 'Child cannot articulate the difference, saying it''s just ''more work''.', 'If you flip it twice and get 2 Heads, does that mean the coin ONLY lands on Heads?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_M', 'P2f', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'You and your friend both want to sit in the front seat of the car. You suggest flipping a coin: ''Heads I win, Tails I win.'' Is that a fair way to decide? Why or why not?', 'Child recognizes the trick and states it is unfair because the friend has zero chance of winning.', 'Child agrees, missing the linguistic trick.', 'What rule would make it exactly fair for both of you?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L1_A', 'P2g', 1, 'A', 'Physical comparison', 'Two handfuls of coins or small items (one large pile, one small pile)', NULL, NULL, NULL, NULL, 'Show the two piles. Say: ''Pile A is my money. Pile B is your money. Without counting, whose pile looks like it has more? Now count them to prove it.''', 'Child visually estimates correctly, then verifies by counting and comparing the two totals.', 'Child counts but cannot articulate which is larger, or miscounts significantly.', 'Did the larger looking pile actually have more when you counted it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L1_B', 'P2g', 1, 'B', 'Physical comparison', 'Two short lists of family/friends (e.g., ''People who like dogs'', ''People who like cats'')', NULL, NULL, NULL, NULL, 'Show the lists. Say: ''Look at the names under Dogs and the names under Cats. Which list is longer? Who has more people on their side?''', 'Child compares the physical length of the lists or counts the names to determine the larger group.', 'Child guesses or focuses on a specific name.', 'If I add your name to the shorter list, which list has more people now?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L1_C', 'P2g', 1, 'C', 'Physical comparison', 'Two small groups of objects representing votes (e.g., 5 red blocks for ''Pizza'', 3 blue blocks for ''Burger'')', NULL, NULL, NULL, NULL, 'Set up the blocks. Say: ''The red blocks are votes for Pizza. The blue blocks are votes for Burgers. Which food got more votes?''', 'Child visually compares the groups and correctly identifies the larger one.', 'Child guesses or misinterprets the colors.', 'How many more votes did Pizza get than Burgers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L2_A', 'P2g', 2, 'A', 'Comparing tally charts', NULL, NULL, NULL, NULL, NULL, 'Show two tally charts. Chart 1 (Class A): Dogs(III), Cats(II). Chart 2 (Class B): Dogs(II), Cats(IIII). Say: ''Which class liked Dogs more?''', 'Child reads both charts and identifies Class A (3 vs 2).', 'Child looks at only one chart, or miscounts tallies.', 'Which class liked Cats more?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L2_B', 'P2g', 2, 'B', 'Comparing bar graphs', NULL, NULL, NULL, NULL, NULL, 'Show two simple bar graphs side-by-side. Graph 1 (Monday): Apples(4), Oranges(2). Graph 2 (Tuesday): Apples(1), Oranges(5). Say: ''On which day were more apples eaten?''', 'Child reads the ''Apples'' bar on both graphs and identifies Monday.', 'Child looks at the tallest bar overall (Oranges on Tuesday), instead of the specific category requested.', 'On which day were more oranges eaten?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L2_C', 'P2g', 2, 'C', 'Comparing totals from data', NULL, NULL, NULL, NULL, NULL, 'Show two lists. Group 1: 3 boys, 4 girls. Group 2: 5 boys, 1 girl. Say: ''Which group has more children in total?''', 'Child adds the numbers for each group (3+4=7, 5+1=6) and identifies Group 1 as larger.', 'Child picks Group 2 because 5 is the biggest single number.', 'How did you find the total for each group before comparing them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L3_A', 'P2g', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show two lists. Class A asked 10 kids: 6 like Red, 4 like Blue. Class B asked 100 kids: 50 like Red, 50 like Blue. Say: ''My friend says Red is more popular in Class B because 50 is bigger than 6. Are they right? Why?''', 'Child explains that 50 out of 100 is half, while 6 out of 10 is more than half, so Red is more popular *in proportion* in Class A.', 'Child agrees with the friend based only on the raw numbers.', 'If Class A had asked 100 kids, and they all answered the same way, how many would like Red?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L3_B', 'P2g', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show two bar graphs with different scales. Graph 1 (scale by 1s) shows a bar reaching the top line (value 5). Graph 2 (scale by 10s) shows a short bar (value 20). Say: ''My friend says the first graph has more because the bar is taller. Why are they wrong?''', 'Child explains that the scale numbers determine the value, not just the physical height of the bar.', 'Child agrees that the taller bar means more.', 'What number should you look at to find out exactly how much each bar represents?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L3_C', 'P2g', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a tally chart for Class A (10 votes total) and Class B (5 votes total). Say: ''My friend compared these two classes and decided Class A likes Pizza more than Class B. But they asked twice as many people in Class A! Is this a fair comparison? Why?''', 'Child recognizes that differing sample sizes can distort straight comparisons.', 'Child thinks the comparison is fair.', 'How could you make the comparison fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_A', 'P2g', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create two short lists of data (e.g., votes for games) for two different teams, where Team A has a higher total number of votes, but Team B has more votes for a specific game (like Tag).'' ', 'Child constructs data satisfying both conditions.', 'Child creates data that violates one or both conditions, or uses abstract numbers without context.', 'How did you make sure Team B had more votes for Tag even though Team A had more total votes?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_B', 'P2g', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Draw two simple bar graphs next to each other that look identical, but tell me a story about why the first graph actually represents a much larger number than the second graph.''', 'Child explains that the scales on the sides of the graphs would be different (e.g., one goes by 1s, the other by 100s).', 'Child cannot explain how identical bars can represent different amounts.', 'Where on the graph do you write the numbers that change the scale?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_C', 'P2g', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me the steps for comparing two different tally charts to find out which chart has the highest single category overall.''', 'Child explains a systematic process of finding the highest tally in chart A, then finding the highest tally in chart B, and finally comparing those two numbers.', 'Child gives a confusing or incomplete explanation, or suggests guessing.', 'What if the highest category in Chart A is a tie? How does that change your steps?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_M', 'P2g', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Two classes are collecting cans for recycling. Class A collected 2 bags, and Class B collected 4 boxes. Class B is celebrating because they think they collected more. What do they need to know before they celebrate?', 'Child points out that they need to know how many cans are in a bag versus a box (the units/amounts are not directly comparable).', 'Child agrees Class B won because 4 is more than 2.', 'If one box holds 10 cans, and one bag holds 50 cans, who actually collected more?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

