INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_A', 'M2', 1, 'A', 'Physical modeling', '24 small objects (e.g., beans or blocks)', NULL, NULL, NULL, NULL, 'Say: ''We are planting a small garden. Make 3 rows, and put 4 plants in each row. How many plants did we use in total?''', 'Child arranges objects into a 3x4 array and correctly counts 12 total.', 'Child makes uneven rows, random groups, or miscounts.', 'How does arranging them in rows make it easier to count them all?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_B', 'M2', 1, 'B', 'Physical modeling', 'A box or outline on paper, Small square tiles or blocks', NULL, NULL, NULL, NULL, 'Say: ''This box is the floor of a new room. We are laying square tiles. Put 5 tiles in a row along one wall, and keep making rows until you have 4 rows. How many tiles cover the floor?''', 'Child creates a 4x5 array inside the boundary and counts 20 total tiles.', 'Child places tiles randomly without rows, or miscounts the total.', 'If we took away one entire row, how many tiles would be left?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_C', 'M2', 1, 'C', 'Physical modeling', 'Paper, Pencil, 15 small objects', NULL, NULL, NULL, NULL, 'Say: ''We have 15 books. We want to put them on shelves so that every shelf has exactly 5 books. Make the piles, then draw a picture of the shelves.''', 'Child makes 3 equal piles of 5, then draws a representation showing 3 shelves with 5 items each.', 'Child makes unequal piles, or draws a picture that doesn''t match the physical model.', 'How did you know you needed exactly 3 shelves?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_A', 'M2', 2, 'A', 'Structured translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''A baker has 4 trays of cookies. Each tray holds 6 cookies. Draw a picture of the trays, then write a math sentence (equation) that shows how to find the total number of cookies.''', 'Child draws 4 groups of 6 and writes ''4 x 6 = 24'' or ''6 + 6 + 6 + 6 = 24''.', 'Child writes the wrong numbers, adds 4 and 6 to get 10, or draws an incorrect picture.', 'Why did you use the number 6 four times in your model?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_B', 'M2', 2, 'B', 'Structured translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''We are building a fence. The yard is shaped like a rectangle. It is 5 steps long and 3 steps wide. Draw the yard and write an equation to show how many steps of fence we need to go all the way around.''', 'Child draws a rectangle, labels the sides (5, 3, 5, 3), and writes an equation like ''5 + 3 + 5 + 3 = 16''.', 'Child only adds 5 + 3 = 8, forgetting the other two sides.', 'Why are there four numbers in your addition sentence instead of just two?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_C', 'M2', 2, 'C', 'Structured translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''I asked 5 friends what their favorite color is. 3 said Red, 2 said Blue. Draw a bar graph to show this data, then write a math sentence showing the total number of friends I asked.''', 'Child draws a bar graph with ''Red'' at 3 and ''Blue'' at 2, and writes ''3 + 2 = 5''.', 'Child draws the graph incorrectly (e.g., no labels, wrong heights) or writes an incorrect equation.', 'How does your graph show the same information as your math sentence?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_A', 'M2', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''A word problem says: There are 5 cars. Each car has 4 wheels. My friend drew 5 circles and 4 circles, and wrote 5 + 4 = 9 wheels. What is wrong with their model?''', 'Child explains that the friend added cars and wheels together, instead of putting 4 wheels ON EACH of the 5 cars.', 'Child thinks the math is correct because 5 + 4 is 9.', 'How should the drawing look to correctly show wheels on cars?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_B', 'M2', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''The problem is to find the perimeter of a rectangular field that is 6 meters long and 2 meters wide. My friend wrote 6 + 2 = 8 meters. What part of the real world did they forget?''', 'Child identifies that a rectangle has four sides, and the friend only accounted for two of them.', 'Child agrees with the friend''s answer.', 'If you only build 8 meters of fence, what will the field look like?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_C', 'M2', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend collected data on favorite pets. They tallied 4 Dogs, 3 Cats, and 2 Fish. To find the total, they multiplied 4 x 3 x 2. Why does their math model not fit the real world?''', 'Child explains that to find a total number of different things combined, you must add, not multiply.', 'Child thinks multiplying is just another way to get a big total.', 'If you actually multiply 4 x 3 x 2, you get 24. Do you have 24 pets here?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_A', 'M2', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Invent a word problem about our house that requires multiplication to solve it. Tell me the problem, draw a picture to model it, and write the math equation.''', 'Child creates a valid scenario involving equal groups (e.g., ''There are 3 windows, and each has 2 curtains''), models it accurately, and writes the correct equation.', 'Child creates an addition problem (e.g., ''3 windows and 2 doors''), or the model/equation doesn''t match the story.', 'How do you know for sure your story requires multiplication and not just addition?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_B', 'M2', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''I will give you an equation: 4 + 4 + 4 + 4 = 16. Write a short story about building something that uses this equation. Then draw a diagram of what you built.''', 'Child invents a story involving four sides of equal length (like a square fence) or four groups of four items, and draws a matching model.', 'Child just writes an abstract story (''I had 4 numbers and added them'') without a real-world object or diagram.', 'If you changed your story to be about a triangle, what would the equation look like?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_C', 'M2', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Design a simple map of a small park with a path running through it. Write down a set of instructions using steps and directions (left/right) so someone can walk the path. Then, write an equation to show how many total steps long the path is.''', 'Child draws a map, writes clear directional instructions (e.g., ''Walk 10 steps, turn right, walk 5 steps''), and provides the correct total sum.', 'Child''s instructions don''t match the map, or the equation is missing/incorrect.', 'If I walked the path backwards, would the total number of steps be the same? Why?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_M', 'M2', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We need to buy new tiles to cover the bathroom floor completely. We don''t want to buy too many, and we don''t want to run out. What exactly do you need to do to figure out how many tiles to buy?', 'Child describes a process of modeling the area: counting how many tiles fit along the length and width, and multiplying them (or drawing a grid to count the total).', 'Child suggests guessing, or just measuring one side.', 'If you know the floor is 6 tiles long and 5 tiles wide, why do you multiply them instead of adding 6 and 5?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

-- File: english_band_2_strand_1.json
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L1_A', 'ENG_PS2a', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'I am going to say three words. Two words have the same middle sound, but one is different. Listen: ''bat'', ''cat'', ''bit''. Which word sounds different in the middle?', 'Child correctly identifies ''bit''.', 'If wrong, stretch the words: ''b-aaaa-t'', ''c-aaaa-t'', ''b-iiii-t''. Ask them to try again.', 'What sound did you hear in the middle of ''bat''? What about ''bit''?', '{"default":{"words":[["bat","cat","bit"],["hop","mop","cup"],["sit","fit","set"]]},"ug":{"words":[["pan","fan","pin"],["pot","hot","hut"],["tin","bin","ten"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L1_B', 'ENG_PS2a', 1, 'B', 'Physical Sorting', '5 small containers or drawn circles, Small objects or drawn pictures representing short vowel CVC words (e.g., pen, pin, pot, pan, cup)', NULL, NULL, NULL, NULL, 'We have 5 boxes, one for each short vowel sound: /a/, /e/, /i/, /o/, /u/. Pick up an object, say its name, and put it in the box with the matching middle sound.', 'Child sorts the objects into the correct vowel categories.', 'If wrong, ask them to say the word slowly and isolate the middle sound.', 'Why did you put the ''pen'' in that box? What sound is in the middle?', '{"default":{"objects":["pen","pin","pot","pan","cup"]},"ug":{"objects":["tin","pot","pan","cup","bed"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L1_C', 'ENG_PS2a', 1, 'C', 'Verbal Substitution', 'None', NULL, NULL, NULL, NULL, 'Say the word ''mat''. Now, change the /a/ sound in the middle to an /o/ sound. What is the new word?', 'Child successfully produces the new word (''mot'' or similar, depending on prompt). Focus is on sound manipulation, not real words necessarily.', 'If incorrect, say the sounds individually: /m/ /a/ /t/, now /m/ /o/ /t/. Blend them for the child.', 'How did the word change when we swapped the middle sound?', '{"default":{"prompts":[["mat","/o/","mot"],["sit","/e/","set"]]},"ug":{"prompts":[["pan","/i/","pin"],["pot","/u/","put"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L2_A', 'ENG_PS2a', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will say a word. You will say the sounds you hear, and then write the letters. The word is ''dog''.', 'Child says /d/ /o/ /g/ and writes ''dog''.', 'If spelled wrong, point to the incorrect letter and ask: ''What sound does this letter make? Does that match the word we want?''', 'How did you know which vowel to use in the middle?', '{"default":{"words":["dog","cat","pig","sun","hen"]},"ug":{"words":["cat","dog","pig","sun","hen"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L2_B', 'ENG_PS2a', 2, 'B', 'Oral->Written Word Building', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Let''s build a word ladder. Start by writing the word ''sit''. Read it aloud. Now change one letter to make it say ''sat''. Say the word, then write it.', 'Child writes ''sit'', says ''sat'', then writes ''sat''.', 'If they change the wrong letter, have them point to each letter and sound out what they wrote.', 'Which part of the word did you change? Why?', '{"default":{"ladders":[["sit","sat","mat","map"],["pin","pan","pat","pot"]]},"ug":{"ladders":[["pin","pan","pat","pot"],["tin","tan","tap","top"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L2_C', 'ENG_PS2a', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will read a short sentence. Repeat it back to me, then write it down. ''The big pig sat in the mud.''', 'Child repeats the sentence correctly and writes it with mostly accurate phonetic spelling for CVC words.', 'If they miss words, repeat the sentence. If CVC words are misspelled, guide them to sound it out.', 'Read the sentence back to me. Did you include all the words?', '{"default":{"sentences":["The big pig sat in the mud.","A red bug is on the rug."]},"ug":{"sentences":["The big pig sat in the mud.","A red bug is on the mat."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L3_A', 'ENG_PS2a', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Look at this sentence: ''The c-o-t ran after the mouse.'' There is a spelling mistake that changes the meaning. Find the mistake and fix it.', 'Child identifies ''cot'' as incorrect and changes it to ''cat''.', 'If they can''t find it, ask them to read the sentence aloud exactly as it is written.', 'Why doesn''t ''cot'' make sense in this sentence? What is the correct word?', '{"default":{"sentences":[{"text":"The c-o-t ran after the mouse.","error":"cot","fix":"cat"}]},"ug":{"sentences":[{"text":"The c-o-t ran after the rat.","error":"cot","fix":"cat"}]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L3_B', 'ENG_PS2a', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a sentence, but I will make a mistake with one of the words. Listen: ''I used a p-e-n to hold the papers together.'' Did I say that right?', 'Child identifies that ''pen'' is the wrong word and suggests ''pin''.', 'If they miss it, repeat the sentence emphasizing the incorrect word.', 'What does a ''pen'' do? What did I actually need?', '{"default":{"sentences":[{"text":"I used a p-e-n to hold the papers together.","error":"pen","fix":"pin"}]},"ug":{"sentences":[{"text":"I used a p-e-n to hold the cloth together.","error":"pen","fix":"pin"}]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L3_C', 'ENG_PS2a', 3, 'C', 'Nonsense Word Reading', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here is a list of words. Some are real words, and some are nonsense (silly) words. Read each one and tell me if it is real or nonsense: ''bim'', ''cat'', ''zug'', ''mop''.', 'Child correctly reads the words and categorizes them.', 'If they misread a word, ask them to point to each letter and say the sound, then blend.', 'How do you know ''zug'' isn''t a real word?', '{"default":{"words":["bim","cat","zug","mop"]},"ug":{"words":["bim","cat","zug","mop"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_A', 'ENG_PS2a', 4, 'A', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Imagine you are teaching a younger child what a ''short a'' sound is. Explain it to them, and write down three example words to show them.', 'Child can articulate the sound and provides three accurate CVC words with short ''a''.', 'If they struggle to explain, ask them to make the sound first, then think of words that have it in the middle.', 'Why did you choose those three words to show the short ''a'' sound?', '{"default":{"target_vowel":"short a"},"ug":{"target_vowel":"short a"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_B', 'ENG_PS2a', 4, 'B', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the silliest sentence you can using as many short ''i'' CVC words as possible. Say the sentence out loud before you write it.', 'Child orally composes and then writes a sentence containing multiple short ''i'' words.', 'If they struggle, provide a starting word like ''The pig...''', 'Read your sentence to me. Which words have the short ''i'' sound?', '{"default":{"target_vowel":"short i"},"ug":{"target_vowel":"short i"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_C', 'ENG_PS2a', 4, 'C', 'Categorisation & Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Create two lists. At the top of one, write ''-at''. At the top of the other, write ''-in''. Now, write down as many words as you can think of that fit into these two families.', 'Child successfully generates at least 3-4 words for each word family.', 'If they get stuck, offer a starting sound: ''What if we put a /p/ sound in front of -at?''', 'What do all the words in the ''-at'' list have in common?', '{"default":{"families":["-at","-in"]},"ug":{"families":["-at","-in"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_M', 'ENG_PS2a', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We are going to write a short shopping list. I need a pen, a pan, and a mop. Say the items back to me, and then write the list.', 'Child accurately repeats the items and spells ''pen'', ''pan'', and ''mop'' correctly on the list.', 'Do not correct them during the task. If failed, return to Execute level tasks focusing on those specific vowel sounds.', 'Read your list back to me to make sure we have everything.', '{"default":{"list":["pen","pan","mop"]},"ug":{"list":["tin","pan","cup"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L1_A', 'ENG_PS2b', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to the start of these two words: ''stop'' and ''sop''. In one of these words, I hear two consonant sounds pushed together at the beginning. Which word is it?', 'Child identifies ''stop'' and can isolate the /s/ and /t/ sounds.', 'If incorrect, exaggerate the sounds: /s/-/t/-op vs /s/-op.', 'What two sounds did you hear at the start of ''stop''?', '{"default":{"word_pairs":[["stop","sop"],["play","pay"],["fast","fat"]]},"ug":{"word_pairs":[["stop","sop"],["play","pay"],["fast","fat"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L1_B', 'ENG_PS2b', 1, 'B', 'Physical Manipulation', 'Two small objects (like stones or beads)', NULL, NULL, NULL, NULL, 'Place the two stones far apart. Say /s/ for one stone, and /p/ for the other. Now push the stones together quickly and say the sounds together: /sp/. What word starts with /sp/?', 'Child successfully blends the sounds and suggests a word like ''spot'' or ''spin''.', 'If they struggle, guide their hands to push the stones while you say the sounds with them.', 'How is /sp/ different from just /s/ or /p/?', '{"default":{"blends":["sp","cl","tr"]},"ug":{"blends":["sp","cl","tr"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L1_C', 'ENG_PS2b', 1, 'C', 'Verbal Identification', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a word slowly: /f/ /l/ /a/ /g/. Can you push those sounds together and tell me the word?', 'Child says ''flag''.', 'If incorrect, say it a bit faster: /fl/ /ag/.', 'What two sounds do you hear at the very beginning of the word?', '{"default":{"words":["flag","crab","jump"]},"ug":{"words":["flag","crab","jump"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L2_A', 'ENG_PS2b', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will say a word. You say the sounds, and then write it. The word is ''frog''. Make sure you hear all the sounds at the beginning.', 'Child says /f/ /r/ /o/ /g/ and writes ''frog''.', 'If they write ''fog'', ask: ''Read what you wrote. Does that say frog or fog?''', 'What two letters are making the beginning sounds?', '{"default":{"words":["frog","slip","tent"]},"ug":{"words":["frog","slip","tent"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L2_B', 'ENG_PS2b', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''lap''. Say it aloud. Now, put a ''c'' sound at the beginning. Say the new word, then write it.', 'Child writes ''lap'', says ''clap'', and writes ''clap''.', 'If incorrect, segment the sounds for them: /c/ /l/ /a/ /p/.', 'What happened to the word when we added the ''c''?', '{"default":{"transformations":[["lap","clap"],["pot","spot"]]},"ug":{"transformations":[["lap","clap"],["pot","spot"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L2_C', 'ENG_PS2b', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Repeat this sentence, then write it: ''The frog sat on the log.''', 'Child repeats and accurately spells ''frog'' including the blend.', 'If ''frog'' is misspelled, focus just on that word and have them stretch out the sounds.', 'Read the sentence. Does the word start with an ''f'' sound and an ''r'' sound?', '{"default":{"sentences":["The frog sat on the log.","The crab ran fast."]},"ug":{"sentences":["The frog sat on the log.","The crab ran fast."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L3_A', 'ENG_PS2b', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Look at this sentence: ''I have a red s-l-e-d for the snow.'' Wait, that''s not right. It should say ''I have a red s-e-d for the snow.'' Or should it? Which word is correct?', 'Child identifies ''sled'' as the correct word.', 'If unsure, have them read both ''sled'' and ''sed'' and see which makes sense.', 'Why do we need the ''l'' in sled?', '{"default":{"words":["sled","sed"]},"ug":{"words":["drum","dum"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L3_B', 'ENG_PS2b', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''The baby will c-r-e-e-p on the floor.'' Now listen to this one: ''The baby will c-e-e-p on the floor.'' Which one sounds right?', 'Child identifies ''creep''.', 'If they miss the blend, repeat both words emphasizing the /r/.', 'What sound was missing in the second word?', '{"default":{"sentences":["The baby will creep on the floor.","The baby will ceep on the floor."]},"ug":{"sentences":["The baby will creep on the mat.","The baby will ceep on the mat."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L3_C', 'ENG_PS2b', 3, 'C', 'Fill in the blank', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here is a word with a blank at the beginning: ''__op''. Should we put ''st'', ''fl'', or ''cr'' at the beginning to make it the word for what you do at a red light?', 'Child selects ''st'' to make ''stop''.', 'If they guess wrong, sound out the incorrect options with them: ''fl-op? cr-op?''', 'Why wouldn''t ''flop'' work for a red light?', '{"default":{"target":"stop","options":["st","fl","cr"],"clue":"red light"},"ug":{"target":"stop","options":["st","fl","cr"],"clue":"red light"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_A', 'ENG_PS2b', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the blend ''pl'' at the top of your paper. Say the sound out loud. Now, write three real words that start with that blend.', 'Child accurately generates and writes three words starting with ''pl'' (e.g., play, plum, plan).', 'If they write words that just start with ''p'', remind them to make the /p/ /l/ sound together.', 'Read your words. Do they all start with the same two sounds?', '{"default":{"blend":"pl"},"ug":{"blend":"pl"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_B', 'ENG_PS2b', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of an animal whose name starts with a blend, like a frog or a crab. Tell me a sentence about what that animal is doing, and then write it down.', 'Child orally composes and writes a sentence featuring an animal name with an initial blend.', 'If they choose an animal without a blend (like ''dog''), redirect them: ''Dog starts with one consonant sound. Can you think of one with two, like sn-ake?''', 'Which word in your sentence has a consonant blend?', '{"default":{"theme":"animals with blends"},"ug":{"theme":"animals with blends"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_C', 'ENG_PS2b', 4, 'C', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me the difference between the word ''tap'' and the word ''trap''. What extra sound did we add, and where is it?', 'Child clearly explains that the /r/ sound was added after the /t/.', 'If they can''t explain, ask them to write both words and circle the difference.', 'How does adding that one letter change the meaning of the word?', '{"default":{"word_pair":["tap","trap"]},"ug":{"word_pair":["tap","trap"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_M', 'ENG_PS2b', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Look around the room or outside. Tell me one thing you see that has a consonant blend in its name (like a plant, a step, or the sky). Say it in a sentence, and then write the sentence.', 'Child successfully identifies an object with a blend, composes a sentence orally, and writes it accurately.', 'Do not correct during the task. If they fail to identify a blend or spell it correctly, review Execute level tasks.', 'Show me the word in your sentence that has the blend. What two sounds are pushed together?', '{"default":{"prompt":"Look around the room or outside."},"ug":{"prompt":"Look around the room or outside."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L1_A', 'ENG_PS2c', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to these words: ''ship'', ''shoe'', ''sun''. Two of these words start with a special sound made by two letters working together to make one new sound: /sh/. Which word does NOT start with the /sh/ sound?', 'Child identifies ''sun''.', 'If incorrect, emphasize the initial sounds: /sh/-ip, /sh/-oe, /s/-un.', 'What sound did ''sun'' start with? How is it different from the other two?', '{"default":{"words":["ship","shoe","sun"]},"ug":{"words":["shop","shoe","sun"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L1_B', 'ENG_PS2c', 1, 'B', 'Physical Manipulation', 'Letter tiles or cards: c, s, h, t', NULL, NULL, NULL, NULL, 'Put the ''s'' tile and the ''h'' tile together. When they stand next to each other, they don''t say /s/ /h/ anymore. They make a totally new sound: /sh/ (like telling someone to be quiet). Now put ''c'' and ''h'' together. They say /ch/ (like a train). Pick up the tiles that make the /sh/ sound.', 'Child selects ''sh''.', 'If wrong, repeat the sound association (quiet vs train).', 'Why do these two letters make only one sound now?', '{"default":{"digraphs":["sh","ch"]},"ug":{"digraphs":["sh","ch"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L1_C', 'ENG_PS2c', 1, 'C', 'Verbal Identification', 'None', NULL, NULL, NULL, NULL, 'I will say a word. If it starts with the /ch/ sound, say ''choo choo!''. If it doesn''t, just shake your head. Ready? ''Chip''.', 'Child responds appropriately (''choo choo!'').', 'If they miss it, exaggerate the /ch/ sound.', 'What sound did you hear at the beginning of ''chip''?', '{"default":{"words":[["chip",true],["cat",false],["chop",true]]},"ug":{"words":[["chop",true],["cup",false],["chin",true]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L2_A', 'ENG_PS2c', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a word. You say the sounds, and then write the letters. Remember, some sounds need two letters! The word is ''shop''.', 'Child says /sh/ /o/ /p/ and writes ''shop''.', 'If they write ''sop'', ask: ''Does your word say shop or sop?'' Remind them of the two letters needed for /sh/.', 'Which two letters work together to make the first sound in that word?', '{"default":{"words":["shop","chip","thin"]},"ug":{"words":["shop","chip","thin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L2_B', 'ENG_PS2c', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''ship''. Say it loud. Now, change the /sh/ sound to a /ch/ sound. Say the new word, then write it.', 'Child writes ''ship'', says ''chip'', and writes ''chip''.', 'If incorrect, point to the ''sh'' and ask what it says, then ask what ''ch'' says.', 'What letters did you have to change to make the new word?', '{"default":{"ladders":[["ship","chip"],["thin","chin"]]},"ug":{"ladders":[["shop","chop"],["thin","chin"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L2_C', 'ENG_PS2c', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''The fish took a bath.'' Say it back to me, then write it down.', 'Child repeats and accurately spells ''fish'' (ending ''sh'') and ''bath'' (ending ''th'').', 'If digraphs are misspelled, isolate the word: ''What two letters make the /sh/ sound at the end of fish?''', 'Look at the end of the word ''bath''. What two letters are making the final sound?', '{"default":{"sentences":["The fish took a bath."]},"ug":{"sentences":["The fish took a bath."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L3_A', 'ENG_PS2c', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this sentence carefully: ''The dog sat in the s-a-d-e.'' That doesn''t look right. What word should it be, and how do we spell the sound at the beginning?', 'Child identifies the word should be ''shade'' and that ''sh'' is missing.', 'If they read it as ''shade'', ask them to look at the letters again. ''Does s-a-d-e say shade?''', 'Why do we need an ''h'' after the ''s'' in this word?', '{"default":{"sentence":"The dog sat in the sade.","error":"sade","fix":"shade"},"ug":{"sentence":"The dog sat in the sade.","error":"sade","fix":"shade"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L3_B', 'ENG_PS2c', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this silly sentence: ''I need to s-o-p vegetables for dinner.'' Did I say that correctly?', 'Child identifies the error and corrects it to ''chop''.', 'If missed, repeat: ''Does s-o-p sound like what you do to vegetables?''', 'What two letters should be at the beginning of ''chop''?', '{"default":{"sentence":"I need to sop vegetables for dinner.","error":"sop","fix":"chop"},"ug":{"sentence":"I need to sop the cabbage for dinner.","error":"sop","fix":"chop"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L3_C', 'ENG_PS2c', 3, 'C', 'Fill in the blank', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here is a word: ''__ip''. We want it to be the word for a big boat. Should we put ''sh'', ''ch'', or ''th'' at the beginning?', 'Child selects ''sh'' to make ''ship''.', 'If incorrect, read the options aloud: ''chip? thip?''', 'Why wouldn''t ''ch'' work in this blank?', '{"default":{"target":"ship","options":["sh","ch","th"],"clue":"a big boat"},"ug":{"target":"ship","options":["sh","ch","th"],"clue":"a big boat on the lake"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_A', 'ENG_PS2c', 4, 'A', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'How would you explain the difference between a blend (like ''sl'') and a digraph (like ''sh'') to someone learning to read? Write down one example of each.', 'Child explains that a blend is two sounds pushed together, but a digraph is two letters making one completely new sound.', 'If they struggle, ask: ''In sl-, can you hear the s and the l? In sh-, can you hear the s and the h?''', 'Why is ''sh'' a digraph and not a blend?', '{"default":{"concept":"blend vs digraph"},"ug":{"concept":"blend vs digraph"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_B', 'ENG_PS2c', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of a word that ends in ''th'', like ''math'' or ''bath''. Tell me a sentence using that word, and then write it down.', 'Child orally composes and writes a sentence using a word with a final ''th'' digraph.', 'If they pick a word starting with ''th'' (like ''the''), redirect them to find one that ends with it.', 'Point to the two letters that make the /th/ sound in your sentence.', '{"default":{"target":"ends in ''th''"},"ug":{"target":"ends in ''th''"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_C', 'ENG_PS2c', 4, 'C', 'Categorisation & Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Make two columns on your paper. Label one ''Starts with CH'' and the other ''Starts with SH''. Write two real words in each column. Say them aloud as you write them.', 'Child accurately generates two ''ch'' words and two ''sh'' words and places them in the correct columns.', 'If they struggle to think of words, offer clues (e.g., ''What do you do with an axe?'' -> chop).', 'How are the sounds in the first column different from the sounds in the second column?', '{"default":{"columns":["ch","sh"]},"ug":{"columns":["ch","sh"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_M', 'ENG_PS2c', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We need to leave a short note. Think of a short sentence telling someone to do something, using a word with ''sh'' or ''ch'' (like ''shut the door'' or ''chop the wood''). Say the sentence to me, then write the note.', 'Child correctly composes and writes a functional sentence utilizing a digraph.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Read the note back to me. Did you use the two letters that work together to make one sound?', '{"default":{"examples":["shut the door","chop the wood"]},"ug":{"examples":["shut the door","chop the wood"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L1_A', 'ENG_PS2d', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to the word ''mad''. Now listen to the word ''made''. How did the vowel sound in the middle change?', 'Child identifies that ''mad'' has a short /a/ and ''made'' has a long /a/ (saying its name).', 'If they struggle, say ''m-aaaa-d'' vs ''m-ayyyy-d'' slowly.', 'What is the difference between the vowel sound in mad and made?', '{"default":{"pairs":[["mad","made"],["hop","hope"],["sit","site"]]},"ug":{"pairs":[["tap","tape"],["not","note"],["bit","bite"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L1_B', 'ENG_PS2d', 1, 'B', 'Physical Manipulation', 'Paper, Pencil, A small stick or pencil to act as a ''magic wand''', NULL, NULL, NULL, NULL, 'Write ''tap''. Now, use your ''magic e'' wand (pencil) and point to the end of the word. The ''e'' tells the vowel to say its name. Say the new word.', 'Child touches the end of the word and says ''tape''.', 'If they say ''tap-e'', remind them the ''e'' is silent, it just does magic on the vowel.', 'What does the magic ''e'' tell the vowel to do?', '{"default":{"words":["tap","kit","rob"]},"ug":{"words":["tap","kit","not"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L1_C', 'ENG_PS2d', 1, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at these two words: ''ran'' and ''rain''. In the second word, the ''a'' and ''i'' are a team working together. The first one does the talking and says its name. What does ''rain'' say?', 'Child correctly reads ''rain''.', 'If they read ''ran-in'', explain the vowel team rule: ''When two vowels go walking, the first one does the talking.''', 'Which letter does the talking in ''ai''?', '{"default":{"words":[["ran","rain"],["met","meet"],["got","goat"]]},"ug":{"words":[["ran","rain"],["bed","bead"],["cot","coat"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L2_A', 'ENG_PS2d', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a word that has a long vowel sound. You need a magic ''e'' at the end to make it happen. The word is ''cake''. Say it, stretch it, write it.', 'Child says /c/ /a/ /k/ and writes ''cake''.', 'If they write ''cak'', ask: ''Does this say cake or cak? What is missing?''', 'Why did you put an ''e'' at the end of the word?', '{"default":{"words":["cake","bike","home","cute"]},"ug":{"words":["cake","bite","hole","tube"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L2_B', 'ENG_PS2d', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write ''boat''. Now, change the first letter to make it say ''coat''. Say the new word, then write it. Remember the vowel team ''oa''.', 'Child writes ''boat'', says ''coat'', and writes ''coat''.', 'If they spell ''cote'', remind them we are using the vowel team ''oa'' for this list.', 'What two letters make the long /o/ sound in coat?', '{"default":{"words":[["boat","coat"],["rain","train"]]},"ug":{"words":[["boat","goat"],["rain","train"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L2_C', 'ENG_PS2d', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''Take the bike to the gate.'' Say it back to me, then write it down.', 'Child repeats the sentence and correctly spells ''take'', ''bike'', and ''gate'' using the magic ''e''.', 'If a word is spelled wrong, focus on the missing silent ''e''.', 'Look at the words take, bike, and gate. What do they all have at the end?', '{"default":{"sentences":["Take the bike to the gate."]},"ug":{"sentences":["Take the bike to the gate."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L3_A', 'ENG_PS2d', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this sentence: ''I h-o-p to see you soon.'' Look at the word ''hop''. Should it be hop, or hope? How do we fix it?', 'Child identifies the error, says ''hope'', and adds an ''e''.', 'If they don''t see it, ask them to read the sentence literally. ''I hop to see you soon.''', 'Why does adding an ''e'' change hop into hope?', '{"default":{"sentence":"I hop to see you soon.","error":"hop","fix":"hope"},"ug":{"sentence":"I hop to see you soon.","error":"hop","fix":"hope"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L3_B', 'ENG_PS2d', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to my sentence: ''The t-r-a-n is on the tracks.'' Did I pronounce that correctly for a big machine on tracks?', 'Child identifies the error and corrects it to ''train''.', 'If they agree, say: ''Tran? Or train?''', 'What sound did I miss in the middle of ''train''?', '{"default":{"sentence":"The t-r-a-n is on the tracks.","error":"tran","fix":"train"},"ug":{"sentence":"The b-o-t is on the lake.","error":"bot","fix":"boat"}}', 0);